noncompliant:
void f(int x, bool b) {
  int y = 4;
  if (b) {
    int x = 7; // Noncompliant: the parameter "x" is shadowed
    int y = 9; // Noncompliant: the local variable "y" is shadowed
    // ...
  }
}

class Foo {
private:
  int myField;

public:
  void doSomething() {
    int myField = 0; // Noncompliant: Foo::myField is shadowed
    // ...
  }
};

compliant:
void f(int x, bool b) {
  int y = 4;
  if (b) {
    int z = 7; // Compliant: different name, no shadowing
    int w = 9; // Compliant: different name, no shadowing
    // ...
  }
}

class Foo {
private:
  int myField;

public:
  void doSomething() {
    int localValue = 0; // Compliant: different name
    this->myField = localValue; // Compliant: explicit reference
  }
};
